import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as i,c as s,a as e,b as a,d as r,e as d}from"./app-706bfe03.js";const l={},c=d('<h1 id="对交互的性能优化" tabindex="-1"><a class="header-anchor" href="#对交互的性能优化" aria-hidden="true">#</a> 对交互的性能优化</h1><h2 id="输入延迟" tabindex="-1"><a class="header-anchor" href="#输入延迟" aria-hidden="true">#</a> 输入延迟</h2><p>输入延迟 ( Input delay ) 是指从交互 ( 如 click、tap、keypress ) 开始，到事件回调开始运行的时间。</p><p>交互总会有一定的输入延迟，因为操作系统需要时间识别输入事件并传递给浏览器，这是不可避免的。我们可以优化的是页面其他部分对输入延迟的影响。</p><h3 id="避免重复的计时器" tabindex="-1"><a class="header-anchor" href="#避免重复的计时器" aria-hidden="true">#</a> 避免重复的计时器</h3><p>setTimeout 和 setInterval 会导致输入延迟。尤其是 setInterval，它会周期性注册回调事件，这增大了输入延迟增大的概率。</p><p>下图显示了 setInterval 是如何导致输入延迟的。</p><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/tjzVtS9wFXxd06gaPHNY.png" alt=""></p><h3 id="避免长任务" tabindex="-1"><a class="header-anchor" href="#避免长任务" aria-hidden="true">#</a> 避免长任务</h3><p>浏览器处理交互是在主线程完成的，而 JavaScript 的长任务会阻塞主线程，因此减少长任务可以减少输入延迟。具体做法参考《JS长任务》的内容。</p><h3 id="交互重叠" tabindex="-1"><a class="header-anchor" href="#交互重叠" aria-hidden="true">#</a> 交互重叠</h3><p>交互重叠 ( interaction overlap ) 是指与一个元素交互后，渲染下一帧之前，又进行了交互。其实就是用户在短时间内进行了多次交互，常见于用户键盘输入、鼠标拖拽等。</p><p>解决办法如下：</p>',13),h=e("li",null,"用 debounce 限制执行次数",-1),p={href:"https://developer.mozilla.org/docs/Web/API/AbortController/abort",target:"_blank",rel:"noopener noreferrer"},_=e("li",null,"尽量使用 CSS 动画，尽量不直接操作动画帧。",-1),u=e("h2",{id:"参考",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#参考","aria-hidden":"true"},"#"),a(" 参考")],-1),f={href:"https://web.dev/optimize-input-delay",target:"_blank",rel:"noopener noreferrer"};function m(b,x){const t=o("ExternalLinkIcon");return i(),s("div",null,[c,e("ul",null,[h,e("li",null,[a("如果事件会触发网络请求，可以使用 "),e("a",p,[a("AbortController"),r(t)]),a(" 取消 fetch")]),_]),u,e("p",null,[e("a",f,[a("optimize-input-delay"),r(t)])])])}const g=n(l,[["render",m],["__file","3.6.交互.html.vue"]]);export{g as default};
